package main

import (
	"context"
	"fmt"
	"net"
	"strings"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server"
	"go.flipt.io/flipt/internal/server/auth"
	authtoken "go.flipt.io/flipt/internal/server/auth/method/token"
	"go.flipt.io/flipt/internal/storage/sql/sqlite"
	authsql "go.flipt.io/flipt/internal/storage/auth/sql"
	oplocksql "go.flipt.io/flipt/internal/storage/oplock/sql"
	pb "go.flipt.io/flipt/rpc/flipt"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/metadata"
	"google.golang.org/protobuf/types/known/timestamppb"

	// SQLite driver
	_ "github.com/mattn/go-sqlite3"
)

// TestRegression covers two authentication bugs:
// 1. Cookie-based tokens are not extracted from HTTP cookies
// 2. Authentication middleware is enforced on all servers with no per-server bypass
func TestRegression(t *testing.T) {
	// Set up in-memory SQLite database for testing
	db, err := sqlite.Open("file::memory:")
	require.NoError(t, err)
	defer db.Close()

	logger := zaptest.NewLogger(t)
	defer logger.Sync()

	// Create and run migrations
	migrator := sqlite.NewMigrator(db, logger)
	err = migrator.Up(false)
	require.NoError(t, err)

	// Create stores
	authStore := authsql.NewStore(sqlite.SQLite, &sqlite.Conn{DB: db}, logger)
	operationLockService := oplocksql.New(logger, sqlite.SQLite, &sqlite.Conn{DB: db})

	// Create initial token for testing
	clientToken, _, err := authStore.CreateAuthentication(
		context.Background(),
		&struct {
			Method    authrpc.Method
			ExpiresAt *timestamppb.Timestamp
			Metadata  map[string]string
		}{
			Method: authrpc.Method_METHOD_TOKEN,
		},
	)
	require.NoError(t, err)
	require.NotEmpty(t, clientToken)

	// Start gRPC server with authentication middleware enabled
	lis, err := net.Listen("tcp", "127.0.0.1:0")
	require.NoError(t, err)
	defer lis.Close()

	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(auth.UnaryInterceptor(logger, authStore)),
	)
	defer grpcServer.Stop()

	// Register the Flipt service
	fliptServer := server.New(logger, authStore)
	pb.RegisterFliptServer(grpcServer, fliptServer)

	// Register auth services
	authServer := auth.NewServer(logger, authStore)
	authrpc.RegisterAuthenticationServiceServer(grpcServer, authServer)

	tokenServer := authtoken.NewServer(logger, authStore)
	authrpc.RegisterAuthenticationMethodTokenServiceServer(grpcServer, tokenServer)

	// Start server in background
	go grpcServer.Serve(lis)

	// Connect client
	conn, err := grpc.Dial(lis.Addr().String(), grpc.WithTransportCredentials(insecure.NewCredentials()))
	require.NoError(t, err)
	defer conn.Close()

	client := authrpc.NewAuthenticationMethodTokenServiceClient(conn)

	t.Run("BUG: Cookie-based tokens are not extracted", func(t *testing.T) {
		// This test demonstrates that tokens sent via HTTP cookies are not accepted
		// Browsers naturally send tokens in cookies, but the auth middleware only checks
		// the Authorization header with Bearer format

		ctx := context.Background()

		// Attempt 1: Token in proper Authorization header (should work)
		ctxWithAuth := metadata.AppendToOutgoingContext(
			ctx,
			"authorization", fmt.Sprintf("Bearer %s", clientToken),
		)

		_, err := client.CreateToken(ctxWithAuth, &authrpc.CreateTokenRequest{
			Name:        "test-token",
			Description: "test",
		})
		assert.NoError(t, err, "should authenticate successfully with Bearer token in Authorization header")

		// Attempt 2: Token in cookie header (should work but doesn't - BUG)
		// Simulate how browsers send cookies in gRPC requests
		ctxWithCookie := metadata.AppendToOutgoingContext(
			ctx,
			"cookie", fmt.Sprintf("flipt_client_token=%s", clientToken),
		)

		_, err = client.CreateToken(ctxWithCookie, &authrpc.CreateTokenRequest{
			Name:        "test-token-from-cookie",
			Description: "test from cookie",
		})

		// This SHOULD work (token is valid and present) but fails because the middleware
		// doesn't check cookies
		if err == nil {
			t.Skip("BUG FIXED: Cookies are now being extracted as tokens")
		}

		// Verify it fails with authentication error
		assert.Error(t, err, "cookie-based token should fail with unauthenticated error")
		assert.True(
			t,
			strings.Contains(err.Error(), "Unauthenticated") ||
				strings.Contains(err.Error(), "unauthenticated"),
			"error should indicate unauthenticated, got: %v", err,
		)
	})

	t.Run("BUG: No per-server authentication bypass", func(t *testing.T) {
		// This test demonstrates that there's no way to configure specific services
		// (like authentication/delegation services) to skip authentication

		// Start a second gRPC server that simulates a delegated auth service
		// that needs to operate without authentication for bootstrapping reasons
		lis2, err := net.Listen("tcp", "127.0.0.1:0")
		require.NoError(t, err)
		defer lis2.Close()

		// This new server attempts to register the same auth token service
		// but we want it to NOT require authentication (e.g., for token creation during bootstrap)
		grpcServer2 := grpc.NewServer(
			grpc.UnaryInterceptor(auth.UnaryInterceptor(logger, authStore)),
		)
		defer grpcServer2.Stop()

		authServer2 := auth.NewServer(logger, authStore)
		authrpc.RegisterAuthenticationServiceServer(grpcServer2, authServer2)

		tokenServer2 := authtoken.NewServer(logger, authStore)
		authrpc.RegisterAuthenticationMethodTokenServiceServer(grpcServer2, tokenServer2)

		go grpcServer2.Serve(lis2)

		conn2, err := grpc.Dial(lis2.Addr().String(), grpc.WithTransportCredentials(insecure.NewCredentials()))
		require.NoError(t, err)
		defer conn2.Close()

		client2 := authrpc.NewAuthenticationMethodTokenServiceClient(conn2)

		// Try to create a token without authentication
		// This simulates a bootstrap scenario where no tokens exist yet
		ctx := context.Background()
		_, err = client2.CreateToken(ctx, &authrpc.CreateTokenRequest{
			Name:        "bootstrap-token",
			Description: "token created without authentication",
		})

		// This SHOULD work in a properly designed system (for bootstrap), but fails
		// because there's no way to skip authentication for specific servers
		if err == nil {
			t.Skip("BUG FIXED: Servers can now skip authentication on a per-service basis")
		}

		// Verify it fails because authentication is required
		assert.Error(t, err, "should fail because auth middleware is applied to all services")
		assert.True(
			t,
			strings.Contains(err.Error(), "Unauthenticated") ||
				strings.Contains(err.Error(), "unauthenticated"),
			"error should indicate unauthenticated, got: %v", err,
		)

		// Additional verification: even with a valid token, we cannot bypass the middleware
		// for this particular server instance if we wanted to (design limitation)
		ctxWithAuth := metadata.AppendToOutgoingContext(
			ctx,
			"authorization", fmt.Sprintf("Bearer %s", clientToken),
		)

		_, err = client2.CreateToken(ctxWithAuth, &authrpc.CreateTokenRequest{
			Name:        "token-with-auth",
			Description: "token created with authentication",
		})
		assert.NoError(t, err, "with authentication header, token creation should work")

		// But the design problem remains: there's no configuration option to skip auth
		// for this server instance. If we wanted to run this server without auth,
		// we'd have to instantiate a gRPC server without the auth interceptor at all,
		// but there's no way to register individual services without interceptors.
	})

	t.Run("BUG: Global authentication enforcement", func(t *testing.T) {
		// This test demonstrates the architectural issue: all gRPC services
		// go through the same authentication interceptor chain with no exceptions

		// The ideal design would allow configuration like:
		//   grpcServer := NewGRPCServer()
		//   grpcServer.RegisterService(authService, skipAuth=true)  // <-- Not possible
		//   grpcServer.RegisterService(fliptService, skipAuth=false) // <-- Default

		// But the current implementation doesn't support this.
		// All services registered with the server go through the same chain.

		// Verify that both services are on the same server and both require auth
		authClient := authrpc.NewAuthenticationServiceClient(conn)
		fliptClient := pb.NewFliptClient(conn)

		ctx := context.Background()

		// Without auth, both should fail
		ctxNoAuth := metadata.AppendToOutgoingContext(ctx)

		// Auth service requires authentication
		_, err := authClient.ListAuthentications(ctxNoAuth, &authrpc.ListAuthenticationsRequest{})
		assert.Error(t, err, "auth service should require authentication")

		// Flipt service also requires authentication
		_, err = fliptClient.ListFlags(ctxNoAuth, &pb.ListFlagsRequest{})
		assert.Error(t, err, "flipt service should require authentication")

		// The architectural problem: there's no way to configure
		// the auth service to skip authentication while keeping it enabled for others
		assert.True(t, true, "both services share the same interceptor chain")
	})

	t.Run("Verify authentication works with proper Bearer token", func(t *testing.T) {
		// Sanity check: verify that valid Bearer tokens DO work
		ctxWithAuth := metadata.AppendToOutgoingContext(
			context.Background(),
			"authorization", fmt.Sprintf("Bearer %s", clientToken),
		)

		resp, err := client.CreateToken(ctxWithAuth, &authrpc.CreateTokenRequest{
			Name:        "valid-token",
			Description: "created with valid bearer token",
		})

		assert.NoError(t, err, "should succeed with valid bearer token")
		assert.NotNil(t, resp)
		assert.NotEmpty(t, resp.ClientToken)
	})
}

